                        std::make_unique<FixedBackOffStrategy>(
                            GrpcMuxFailover<RQ, RS>::DefaultFailoverBackoffMilliseconds),
                        rate_limit_settings, GrpcStream<RQ, RS>::ConnectedStateValue::SecondEntry);
                  })
            : absl::nullopt,
        /*grpc_mux_callbacks=*/*this,

